#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>
#include <vector>
#include <algorithm>
#include <iostream>

#ifndef REC_LENGTH
#define REC_LENGTH 49
#endif

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

void nearest_neighbor_kernel(LatLong *locations, float *distances, int numRecords, float lat, float lng) {
    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        float diff_lat = lat - locations[i].lat;
        float diff_lng = lng - locations[i].lng;
        distances[i] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }

    double start_time = 0.0;
    double end_time = 0.0;

    if (timing) {
        start_time = omp_get_wtime();
    }

    nearest_neighbor_kernel(&locations[0], distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
        printf("Kernel execution time: %f seconds\n", end_time - start_time);
    }

    return distances;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    const char* data_folder = getenv("DATA_FOLDER");
    if (!data_folder) {
        data_folder = "."; 
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Could not open filelist: %s\n", filename);
        exit(1);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
            }
            break;
        }
        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;

            if (fgets(record.recString, REC_LENGTH, fp) == NULL) break;

            size_t len = strlen(record.recString);
            if (len > 0 && record.recString[len-1] == '\n') {
                record.recString[len-1] = '\0';
            }

            if (strlen(record.recString) < 38) continue; 

            char substr[6];

            for (i = 0; i < 5 && (28 + i) < len; i++) 
                substr[i] = record.recString[28 + i];
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5 && (33 + i) < len; i++) 
                substr[i] = record.recString[33 + i];
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        if (minLoc != i) {
            tempRec = records[i];
            records[i] = records[minLoc];
            records[minLoc] = tempRec;

            tempDist = distances[i];
            distances[i] = distances[minLoc];
            distances[minLoc] = tempDist;
        }

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        i++;
                        if (i < argc) *lat = atof(argv[i]);
                    } else {
                        i++;
                        if (i < argc) *lng = atof(argv[i]);
                    }
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    if (i < argc) *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    if (i < argc) *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    if (i < argc) {
                        // In OpenMP version, we just store it for loadData to use via env or global
                        // Since we removed global dependency in loadData signature, we set env
                        putenv("DATA_FOLDER", argv[i]);
                    }
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (ignored in OpenMP)\n");
    printf("-d [int]     Choose the device (ignored in OpenMP)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    double total_start = 0.0;
    double total_end = 0.0;
    double init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
           d2h_time = 0, close_time = 0, total_time = 0;

    if (timing) {
        total_start = omp_get_wtime();
    }

    // Initialization (trivial in OpenMP)
    if (timing) {
        init_time = 0.0; // No complex init like OpenCL
    }

    recordDistances = OpenMPFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet) {
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    }

    if (timing) {
        total_end = omp_get_wtime();
        total_time = (total_end - total_start) * 1000.0; // Convert to ms

        // Simulating breakdown for consistency with original output structure
        // In OpenMP, these distinct phases are merged or negligible
        printf("Init: %f\n", init_time);
        printf("MemAlloc: %f\n", mem_alloc_time);
        printf("HtoD: %f\n", h2d_time);
        printf("Exec: %f\n", kernel_time);
        printf("DtoH: %f\n", d2h_time);
        printf("Close: %f\n", close_time);
        printf("Total: %f\n", total_time);
    }

    free(recordDistances);
    return 0;
}
